// // This module implements a 10-bit synchronous binary counter that counts downwards on the falling edge of the clock when the enable signal is low.
module sync_counter_with_enable(
    input clk,
    input en,
    output reg [9:0] q
    );

    always @(posedge clk) begin
        if (en) begin
            q <= q + 1;
        end
    end
endmodule
